def pushMessage(token, title, message):
    r"""推送消息 (使用 HTML 格式以支持换行)"""
    url = f"http://www.pushplus.plus/send?token={token}&title={title}&content={message}&template=html"
    requests.get(url)

if __name__ == '__main__':
    # === 获取我的配置 ===
    MY_APP_TOKEN = os.environ.get("APP_TOKEN")
    MY_USER_ID = os.environ.get("USER_ID")
    MY_PUSHPLUS = os.environ.get("PUSHPLUS_TOKEN")
    
    # === 获取朋友的配置 ===
    FRIEND_APP_TOKEN = os.environ.get("FRIEND_APP_TOKEN")
    FRIEND_USER_ID = os.environ.get("FRIEND_USER_ID")
    
    # 统一生成一个随机步数，确保你们的步数完全一致
    target_step = random.randint(12001, 15301)
    print(f"\n今日统一目标步数已生成: {target_step}")
    
    time_bj = datetime.datetime.today() + datetime.timedelta(hours=8)
    now = time_bj.strftime("%Y-%m-%d %H:%M:%S")
    
    # 我们用一个字符串来收集所有执行日志，用于最后的统一推送
    push_content = f"<b>执行时间：</b>{now}<br><b>目标步数：</b>{target_step} 步<br><br>"
    
    # ---------------- 1. 执行我的账号 ----------------
    print("\n========== 开始处理: 我的账号 ==========")
    if MY_APP_TOKEN and MY_USER_ID:
        brush, message = brushStep(MY_APP_TOKEN, MY_USER_ID, str(target_step))
        log = f"我的账号：[{message}]"
        print(log)
        push_content += f"👉 {log}<br>"
    else:
        print("未配置我的账号 app_token 或 user_id。")
        push_content += "👉 我的账号：未配置或读取失败<br>"

    # ---------------- 2. 执行朋友的账号 ----------------
    print("\n========== 开始处理: 朋友账号 ==========")
    if FRIEND_APP_TOKEN and FRIEND_USER_ID:
        brush, message = brushStep(FRIEND_APP_TOKEN, FRIEND_USER_ID, str(target_step))
        log = f"朋友账号：[{message}]"
        print(log)
        push_content += f"👉 {log}<br>"
    else:
        print("未配置朋友账号 app_token 或 user_id。")
        push_content += "👉 朋友账号：未配置或读取失败<br>"

    # ---------------- 3. 统一发送推送通知 ----------------
    if MY_PUSHPLUS:
        print("\n正在将综合结果推送到您的微信...")
        pushMessage(MY_PUSHPLUS, "双账号刷步通知", push_content)
        print("推送完成！")
    else:
        print("\n未配置 PushPlus Token，不执行推送。")
